sql:
SELECT p.player_name, t.team_name
FROM players p
JOIN teams t ON p.team_id = t.team_id
WHERE p.player_id IN (
    SELECT player_id FROM player_matches WHERE runs > (SELECT AVG(runs) FROM player_matches)
);

